+/// Benchmark: gc_tick with multiple pages queued.
+fn bench_gc_tick(c: &mut Criterion) {
+    let mut group = c.benchmark_group("gc/gc_tick");
+    group.sample_size(50);
+    group.measurement_time(Duration::from_secs(10));
